mapper.select:
SELECT id, title, content, status, category_id, created_at, updated_at
FROM articles
WHERE id = #{id}

mapper.update:
UPDATE articles
SET title = #{title},
    content = #{content},
    status = #{status},
    category_id = #{categoryId}
WHERE id = #{id}

mapper.select:
SELECT id, title, content, status, category_id, created_at, updated_at, source, csdn_article_id, content_hash
FROM articles
WHERE csdn_article_id = #{csdnArticleId}
